var addToArrayForm = function(num, k) {
    const res = [];
    let i = num.length - 1;
    let carry = k;
    while (i >= 0 || carry > 0) {
        if (i >= 0) {
            carry += num[i];
            i--;
        }
        res.push(carry % 10);
        carry = Math.floor(carry / 10);
    }
    res.reverse();
    return res;
};
